class Curvas_1 {
  constructor(fondo, curvas) { this.fondoColor = fondo; this.curvas = curvas; }
  dibujar(pg, opacidad, vib) { 
    pg.background(this.fondoColor); 
    for (let c of this.curvas) c.dibujar(pg, opacidad, vib); 
  }
}

